class Invoice {
    public void printInvoice() {
        System.out.println("This is the content!");
    }
}

class Decorator extends Invoice {
    protected Invoice ticket;
    public Decorator(Invoice t) {
        ticket = t;
    }
    public void printInvoice() {
        if (ticket != null) {
            ticket.printInvoice();
        }
    }
}

class HeadDecorator extends Decorator {
    public HeadDecorator(Invoice t) {
        super(t);
    }
    public void printInvoice() {
        System.out.println("This is the header!");
        ticket.printInvoice();
    }
}

class FootDecorator extends Decorator {
    public FootDecorator(Invoice t) {
        super(t);
    }
    public void printInvoice() {
        ticket.printInvoice();
        System.out.println("This is the footnote!");
    }
}

class Test {
    public static void main(String[] args) {
        Invoice t = new Invoice();
        Invoice ticket;
        ticket = new FootDecorator(new HeadDecorator(t));
        ticket.printInvoice();
        System.out.println("------------------");
        ticket = new HeadDecorator(new FootDecorator(t));
        ticket.printInvoice();
    }
}
